namespace Forge.Api.Data.TrainingContent;

public class EmployeesTraining : TrainingContentBase
{
    public EmployeesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Employees Overview",
            Slug = "employees-overview",
            Summary = "What the Employees module is, the roster and profile views, the detail tabs, and how roles and work location connect to the rest of the system.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/employees"]""",
            Tags = """["employees","hr","people"]""",
            ContentJson = """{"body":"## Employees Overview\n\nThe Employees module is the people directory and HR hub for your shop. It gives Admins and Managers a searchable roster of everyone in the system, plus a rich profile for each person that pulls together employment details, contact information, time, pay, training, compliance, jobs, events, expenses, documents, and an activity trail — all in one place.\n\n### Who Can Access It\n\nThe Employees feature is role-guarded: only **Admin** and **Manager** users can open it. The profile views are read-only here — you browse and review records, but you don't create or edit employees on this page.\n\n### Creating Employees\n\nNew employees are not created inside this feature. The **Invite Employee** button (visible to Admins) sends you to **Admin > Users**, where accounts are created and core fields (role, work location, etc.) are set. The Employees module then surfaces those records as profiles.\n\n### The Roster (List View)\n\nThe list at /employees shows every employee with an avatar and name (rendered Last, First), role, team, job title, email, phone, status, and start date. A filter bar lets you search by name/email/phone, filter by role, and filter by status (Active / Inactive / All). Click any row to open that person's profile.\n\n### The Profile (Detail View)\n\nClicking an employee opens their detail page. The header shows the avatar, name, role chip, and an Active/Inactive status chip, plus quick contact links. Below the header is a stats bar with five clickable cards — Hours this period, Compliance %, Active Jobs, Training %, and Pending Expenses — each of which jumps to the matching tab.\n\nThe profile is organized into ten tabs:\n- **Overview** — employment details, contact info, address, emergency contact, and system access (PIN / RFID / barcode)\n- **Time** — time entries for a selectable period (this week, pay period, this month)\n- **Pay** — pay stubs with gross, deductions, taxes, and net pay\n- **Training** — training module progress and quiz scores\n- **Compliance** — compliance forms and their signed/pending status\n- **Jobs** — active jobs assigned to the employee (click to open in the kanban board)\n- **Events** — upcoming events with RSVP status\n- **Expenses** — expense records and reimbursement status\n- **Documents** — drag-and-drop file storage for the employee\n- **Activity** — a chronological audit trail of record changes\n\nThe active tab is reflected in the URL (e.g., /employees/42/overview) so profiles are shareable and bookmarkable.\n\n### Roles and Work Location\n\n**Role** comes from the system's role list (loaded from the database, not hardcoded) and drives what the person can do across the application (RBAC). It's shown as a chip in the header and is filterable in the roster.\n\n**Work Location** is a link to a Company Location and matters for HR and tax purposes — it determines state withholding and which state's rules apply to the employee. It appears under Employment Details on the Overview tab.\n\n### System Access\n\nThe Overview tab's System Access section shows whether the employee has configured kiosk/shop-floor credentials: a PIN, an RFID/NFC identifier, and a barcode. These let the person clock in and authenticate at shop-floor displays.\n\n### When to Use Employees\n\n- When you need to look up a coworker's role, team, contact info, or work location\n- When reviewing someone's time, pay, training, or compliance status in one place\n- When checking which jobs a person is assigned to\n- When uploading or reviewing employee documents\n- When you need an audit trail of changes to an employee record","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
