            ContentJson = """{"appRoute":"/employees","startButtonLabel":"Tour Employees","steps":[{"element":"[data-testid='employees-invite-btn']","popover":{"title":"Invite Employee","description":"New employees aren't created here — clicking Invite Employee takes Admins to Admin > Users, where accounts are set up. This button only appears for users with the Admin role.","side":"bottom"}},{"element":".filters-bar","popover":{"title":"Search and Filters","description":"Use this bar to narrow the roster. Search by name, email, or phone; filter by Role (loaded from the system role list); and filter by Status — Active, Inactive, or All. Results update in the table below.","side":"bottom"}},{"element":"app-data-table[tableId='employees-list']","popover":{"title":"Employee Roster","description":"Every employee appears here with an avatar and name (shown Last, First), role, team, job title, email, phone, status chip (green Active / gray Inactive), and start date. Click any row to open that person's profile. Sort columns by clicking headers.","side":"top"}},{"element":".ed-header__name","popover":{"title":"Profile Header","description":"On the profile page, the header shows the employee's avatar and name alongside a role chip and an Active/Inactive status chip, plus clickable email and phone links. Use the back link to return to the roster.","side":"bottom"}},{"element":".ed-stats","popover":{"title":"Quick Stat Cards","description":"Five stat cards summarize the employee at a glance: Hours this period, Compliance %, Active Jobs, Training %, and Pending Expenses. Each card is clickable and jumps straight to its matching detail tab.","side":"bottom"}},{"element":".ed-tabs","popover":{"title":"Profile Tabs","description":"The profile is split into ten tabs: Overview, Time, Pay, Training, Compliance, Jobs, Events, Expenses, Documents, and Activity. The active tab is stored in the URL so you can bookmark or share a specific view. Start with Overview for employment details, contact info, and system access.","side":"bottom"}},{"element":".ed-back","popover":{"title":"Back to the Roster","description":"Click here to return to the employee list. From there you can pick another person or adjust your search and filters.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Employees Field Reference",
