            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/employees"]""",
            Tags = """["employees","hr","people","reference"]""",
            ContentJson = """{"title":"Employees Field Reference","groups":[{"heading":"Roster — Filters and Actions","items":[{"label":"Search Employees","value":"Text input. Searches by name, email, or phone. Press Enter to apply."},{"label":"Role filter","value":"Select. Filters the roster by role; options are loaded from the system role list (not hardcoded). Default is '-- All Roles --'."},{"label":"Status filter","value":"Select. Filters by employment status: All, Active, or Inactive."},{"label":"Invite Employee","value":"Green button shown only to Admins. Navigates to Admin > Users to create a new employee — employees are not created on this page. data-testid: employees-invite-btn"}]},{"heading":"Roster Table Columns","items":[{"label":"Name","value":"Avatar plus the employee's name rendered Last, First. Sortable."},{"label":"Role","value":"The employee's role. Sortable and filterable."},{"label":"Team","value":"Team name, or a dash if none. Sortable."},{"label":"Job Title","value":"Job title, or a dash if none. Sortable."},{"label":"Email","value":"Work email. Sortable."},{"label":"Phone","value":"Phone number, or a dash if none. Sortable."},{"label":"Status","value":"Chip: green 'Active' or gray 'Inactive'. Sortable."},{"label":"Start Date","value":"Hire date, formatted MM/dd/yyyy. Sortable (date type)."}]},{"heading":"Profile Header","items":[{"label":"Name","value":"Displayed Last, First (e.g., 'Hartman, Daniel'). Shown next to the avatar."},{"label":"Role chip","value":"The employee's role rendered as an info-colored chip."},{"label":"Status chip","value":"Green 'Active' chip or gray 'Inactive' chip."},{"label":"Contact links","value":"Job title, team, a mailto email link, and a tel phone link appear when present."},{"label":"Back to Employees","value":"Link in the header that returns to the roster. CSS: .ed-back"}]},{"heading":"Profile Stat Cards","items":[{"label":"Hours this period","value":"Total hours for the current period. Click to jump to the Time tab."},{"label":"Compliance %","value":"Percentage of compliance items completed. Click to jump to the Compliance tab."},{"label":"Active Jobs","value":"Count of active jobs assigned. Click to jump to the Jobs tab."},{"label":"Training %","value":"Training progress percentage. Click to jump to the Training tab."},{"label":"Pending Expenses","value":"Count of outstanding expenses. Click to jump to the Expenses tab."}]},{"heading":"Overview Tab — Employment Details","items":[{"label":"Role","value":"The employee's role (RBAC). Always shown."},{"label":"Job Title","value":"Job classification. Optional."},{"label":"Department","value":"Org department. Optional."},{"label":"Team","value":"Team assignment. Optional."},{"label":"Work Location","value":"Linked Company Location. Determines state withholding and which state's rules apply. Optional; defaults to the company's default location when unset."},{"label":"Start Date","value":"Hire date, formatted MM/dd/yyyy. Optional."},{"label":"Status","value":"Active or Inactive chip."}]},{"heading":"Overview Tab — Contact, Address, Emergency, System Access","items":[{"label":"Work Email","value":"Primary work email (mailto link). Always shown."},{"label":"Personal Email","value":"Secondary contact email. Optional."},{"label":"Phone","value":"Phone number (tel link). Optional."},{"label":"Address","value":"Street, city, state, ZIP. Section shows only when a street address exists."},{"label":"Emergency Contact","value":"Name, relationship, and phone. Section shows only when an emergency contact name exists."},{"label":"PIN Configured","value":"Yes/No — whether a kiosk PIN is set up."},{"label":"RFID / NFC","value":"Configured / Not configured — shop-floor badge scan identifier."},{"label":"Barcode","value":"Configured / Not configured — barcode scanner identifier."},{"label":"Compliance counter","value":"Completed / total compliance items (e.g., 3 / 5)."}]},{"heading":"Profile Tabs","items":[{"label":"Overview","value":"Employment details, contact info, address, emergency contact, and system access."},{"label":"Time","value":"Time entries for a selectable period (week, pay period, month). Columns: Date, Duration, Category, Job #, Job Title, Notes, Type (Manual/Auto)."},{"label":"Pay","value":"Pay stubs. Columns: Pay Date, Period Start, Period End, Gross, Deductions, Taxes, Net Pay (currency)."},{"label":"Training","value":"Training records. Columns: Module, Type, Status (chip), Score, Started, Completed."},{"label":"Compliance","value":"Compliance forms. Columns: Form, Type, Status (chip), Signed, Created."},{"label":"Jobs","value":"Active assigned jobs. Columns: Job #, Title, Track, Stage (colored chip), Priority, Due. Rows open the job in the kanban board."},{"label":"Events","value":"Upcoming events. Columns: Title, Type (icon chip), Start, End, Location, Required, RSVP status."},{"label":"Expenses","value":"Expense records. Columns: Date, Category, Description, Amount, Status (chip)."},{"label":"Documents","value":"Drag-and-drop upload zone. Accepts PDF, Word, and images up to 25MB per file."},{"label":"Activity","value":"Chronological audit trail of changes to the employee record."}]},{"heading":"Statuses and Enums","items":[{"label":"Employment status","value":"Active (green chip) or Inactive (gray chip)."},{"label":"Training status","value":"NotStarted (gray), InProgress (blue), Completed (green), Failed (red)."},{"label":"Compliance status","value":"Pending (warning), Signed/Completed (green), Expired (red)."},{"label":"Expense status","value":"Pending (warning), Approved (green), Rejected (red), Reimbursed (info)."},{"label":"Event RSVP","value":"Invited (info), Accepted (green), Declined (red)."}]},{"heading":"Access and Connections","items":[{"label":"Feature access","value":"Role-guarded to Admin and Manager. Profiles are read-only on this page."},{"label":"Creating / editing","value":"Done in Admin > Users, reached via the Invite Employee button (Admins only)."},{"label":"Role","value":"Drives RBAC across the app. Loaded from the system role list, shown as a chip, and filterable in the roster."},{"label":"Work Location","value":"FK to a Company Location. Drives state tax withholding and applicable state rules."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Employees Knowledge Check",
            Slug = "employees-quiz",
            Summary = "Test your knowledge of the Employees module: access, the roster, profile tabs, roles, work location, and system access.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/employees"]""",
            Tags = """["employees","hr","people","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"em1","text":"Who can access the Employees module?","options":[{"id":"a","text":"All authenticated users"},{"id":"b","text":"Only Admins and Managers","isCorrect":true},{"id":"c","text":"Only the employee viewing their own record"},{"id":"d","text":"Anyone with a shop-floor PIN"}],"explanation":"The Employees feature is role-guarded to Admin and Manager users. Other roles cannot open it, and even Admins/Managers see profiles as read-only here."},{"id":"em2","text":"How do you create a new employee?","options":[{"id":"a","text":"Click 'New Employee' on the roster and fill out a dialog"},{"id":"b","text":"Use the Invite Employee button, which takes you to Admin > Users where accounts are created","isCorrect":true},{"id":"c","text":"Right-click the roster table and choose 'Add'"},{"id":"d","text":"Employees are imported automatically from time entries"}],"explanation":"Employees are not created in this feature. The Invite Employee button (shown to Admins) navigates to Admin > Users, where the account and its core fields are set up. The Employees module then displays the resulting profile."},{"id":"em3","text":"In the roster, how is an employee's name displayed?","options":[{"id":"a","text":"First Last (e.g., Daniel Hartman)"},{"id":"b","text":"Last, First (e.g., Hartman, Daniel)","isCorrect":true},{"id":"c","text":"Username only"},{"id":"d","text":"Email address"}],"explanation":"Per the app's naming convention, a person's full name is rendered Last, First — so the roster and profile header show 'Hartman, Daniel' rather than 'Daniel Hartman'."},{"id":"em4","text":"Why does an employee's Work Location matter?","options":[{"id":"a","text":"It sets the color of their avatar"},{"id":"b","text":"It determines state withholding and which state's rules apply","isCorrect":true},{"id":"c","text":"It controls which kanban board they appear on"},{"id":"d","text":"It decides their pay rate"}],"explanation":"Work Location links to a Company Location and drives HR/tax behavior — specifically state withholding and which state's rules apply to the employee. It appears under Employment Details on the Overview tab."},{"id":"em5","text":"You want to see an employee's pay stubs with gross, taxes, and net pay. Which tab do you open?","options":[{"id":"a","text":"Time"},{"id":"b","text":"Pay","isCorrect":true},{"id":"c","text":"Compliance"},{"id":"d","text":"Activity"}],"explanation":"The Pay tab lists pay stubs with columns for Pay Date, Period Start/End, Gross, Deductions, Taxes, and Net Pay. The Time tab is for time entries, not pay."},{"id":"em6","text":"What happens when you click one of the five stat cards in the profile header (e.g., Active Jobs)?","options":[{"id":"a","text":"It opens a printable report"},{"id":"b","text":"It jumps to the matching detail tab (e.g., the Jobs tab)","isCorrect":true},{"id":"c","text":"It edits that statistic inline"},{"id":"d","text":"It refreshes the entire page"}],"explanation":"Each stat card is clickable and navigates straight to its corresponding tab — Hours to Time, Compliance % to Compliance, Active Jobs to Jobs, Training % to Training, and Pending Expenses to Expenses."},{"id":"em7","text":"Where do you filter the roster by a particular role, and where do the role options come from?","options":[{"id":"a","text":"The Role filter in the filter bar; options are loaded from the system role list","isCorrect":true},{"id":"b","text":"The Role filter; options are hardcoded into the component"},{"id":"c","text":"There is no role filter — you must search by name"},{"id":"d","text":"In Admin > Users only"}],"explanation":"The filter bar includes a Role select whose options come from the database-backed system role list (not hardcoded, per the app's rule against hardcoding select options). Pick a role to narrow the roster."},{"id":"em8","text":"The System Access section on the Overview tab tells you what about an employee?","options":[{"id":"a","text":"Their salary and benefits"},{"id":"b","text":"Whether they have a PIN, an RFID/NFC identifier, and a barcode configured","isCorrect":true},{"id":"c","text":"Which managers can approve their time"},{"id":"d","text":"Their last login timestamp"}],"explanation":"System Access shows the kiosk/shop-floor credentials the employee has set up: PIN Configured (Yes/No), RFID/NFC (Configured/Not configured), and Barcode (Configured/Not configured), plus a compliance item counter."},{"id":"em9","text":"How many tabs does the employee profile have, and which one is the default?","options":[{"id":"a","text":"Five tabs, defaulting to Pay"},{"id":"b","text":"Ten tabs, defaulting to Overview","isCorrect":true},{"id":"c","text":"Three tabs, defaulting to Activity"},{"id":"d","text":"Ten tabs, defaulting to Documents"}],"explanation":"The profile has ten tabs — Overview, Time, Pay, Training, Compliance, Jobs, Events, Expenses, Documents, and Activity — and opens on Overview by default. The active tab is stored in the URL."},{"id":"em10","text":"On the Jobs tab, what happens when you click a job row?","options":[{"id":"a","text":"It deletes the job assignment"},{"id":"b","text":"It opens the job in the kanban board","isCorrect":true},{"id":"c","text":"It marks the job complete"},{"id":"d","text":"It exports the job to PDF"}],"explanation":"The Jobs tab lists the employee's active assigned jobs. Clicking a row navigates to that job on the kanban board so you can see it in context."},{"id":"em11","text":"What file types and size does the Documents tab accept?","options":[{"id":"a","text":"Only PDFs, up to 5MB"},{"id":"b","text":"PDF, Word, and images, up to 25MB per file","isCorrect":true},{"id":"c","text":"Any file type, with no size limit"},{"id":"d","text":"Only images, up to 25MB"}],"explanation":"The Documents tab is a drag-and-drop upload zone that accepts PDF, Word, and image files (jpg/jpeg/png), with a 25MB limit per file."},{"id":"em12","text":"On the roster, a column shows a dash instead of a value (e.g., under Team or Phone). What does that mean?","options":[{"id":"a","text":"The data is being loaded and will appear shortly"},{"id":"b","text":"That optional field has no value for the employee","isCorrect":true},{"id":"c","text":"The field is restricted and hidden from you"},{"id":"d","text":"The employee is inactive"}],"explanation":"Optional fields like Team, Job Title, and Phone render a dash when empty. It simply means no value has been entered for that employee — not that the data is hidden or loading."}]}"""
        });

        Log.Information("Seeded Employees training modules");
